export type IntegrationType = 'ga4' | 'search-console';

export interface Integration {
  id: string;
  type: IntegrationType;
  name: string;
  email: string;
  property: string; // GA4 property or SC site
  connectedAt: string;
  status: 'connected' | 'disconnected' | 'error';
}

export interface AttributionKPI {
  aiVisits: number;
  aiConversions: number;
  aiTrafficShare: number; // percentage
  aiAvgCTR: number; // percentage
}

export interface TrafficDataPoint {
  date: string;
  chatgpt: number;
  perplexity: number;
  claude: number;
  gemini: number;
  copilot: number;
}

export interface AttributionRow {
  source: string;
  visits: number;
  pageViews: number;
  avgDuration: string; // "2m 34s"
  bounceRate: number;
  conversions: number;
  trend: number; // percentage
}

export interface AIQuery {
  query: string;
  clicks: number;
  impressions: number;
  ctr: number;
  position: number;
  isAIReferral: boolean;
}

import {
  Integration,
  IntegrationType,
  AttributionKPI,
  TrafficDataPoint,
  AttributionRow,
  AIQuery,
} from '../types/integrations';

const STORAGE_KEY = 'citedby_integrations';

// --- Persistence helpers ---

function loadIntegrations(): Integration[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
}

function saveIntegrations(list: Integration[]): void {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(list));
}

// --- Public API ---

export function getIntegrations(): Integration[] {
  return loadIntegrations();
}

export async function connectIntegration(
  type: IntegrationType
): Promise<Integration> {
  // Simulate a 2-second OAuth flow
  await new Promise((resolve) => setTimeout(resolve, 2000));

  const isGA4 = type === 'ga4';
  const randomId = crypto.randomUUID?.() ?? `int_${Date.now()}`;

  const mockEmails = [
    'analytics@citedby.ai',
    'marketing@monsite.com',
    'data-team@startup.io',
    'webmaster@agence-digitale.fr',
  ];
  const email = mockEmails[Math.floor(Math.random() * mockEmails.length)];

  const ga4Properties = [
    'properties/345678901 - citedby.ai',
    'properties/234567890 - mon-ecommerce.fr',
    'properties/456789012 - app.saas-tool.com',
  ];
  const scSites = [
    'https://citedby.ai',
    'https://www.mon-ecommerce.fr',
    'https://app.saas-tool.com',
  ];

  const property = isGA4
    ? ga4Properties[Math.floor(Math.random() * ga4Properties.length)]
    : scSites[Math.floor(Math.random() * scSites.length)];

  const integration: Integration = {
    id: randomId,
    type,
    name: isGA4 ? 'Google Analytics 4' : 'Google Search Console',
    email,
    property,
    connectedAt: new Date().toISOString(),
    status: 'connected',
  };

  const current = loadIntegrations().filter((i) => i.type !== type);
  current.push(integration);
  saveIntegrations(current);

  return integration;
}

export function disconnectIntegration(id: string): void {
  const current = loadIntegrations().filter((i) => i.id !== id);
  saveIntegrations(current);
}

// --- Mock data generators ---

function randomBetween(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

export function getAttributionKPIs(
  period: '7d' | '30d' | '90d'
): AttributionKPI {
  const multiplier = period === '7d' ? 1 : period === '30d' ? 4 : 12;
  return {
    aiVisits: randomBetween(820, 1350) * multiplier,
    aiConversions: randomBetween(24, 68) * multiplier,
    aiTrafficShare: parseFloat((randomBetween(80, 180) / 10).toFixed(1)),
    aiAvgCTR: parseFloat((randomBetween(25, 72) / 10).toFixed(1)),
  };
}

export function getTrafficData(
  period: '7d' | '30d' | '90d'
): TrafficDataPoint[] {
  const days = period === '7d' ? 7 : period === '30d' ? 30 : 90;
  const points: TrafficDataPoint[] = [];
  const now = new Date();

  for (let i = days - 1; i >= 0; i--) {
    const d = new Date(now);
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().slice(0, 10);

    points.push({
      date: dateStr,
      chatgpt: randomBetween(30, 150),
      perplexity: randomBetween(10, 60),
      claude: randomBetween(15, 80),
      gemini: randomBetween(20, 90),
      copilot: randomBetween(5, 40),
    });
  }

  return points;
}

