 33→export async function connectIntegration(
 34→  type: IntegrationType
 35→): Promise<Integration> {
 36→  // Simulate a 2-second OAuth flow
 37→  await new Promise((resolve) => setTimeout(resolve, 2000));
 38→
 39→  const isGA4 = type === 'ga4';
 40→  const randomId = crypto.randomUUID?.() ?? `int_${Date.now()}`;
 41→
 42→  const mockEmails = [
 43→    'analytics@citedby.ai',
 44→    'marketing@monsite.com',
 45→    'data-team@startup.io',
 46→    'webmaster@agence-digitale.fr',
 47→  ];
 48→  const email = mockEmails[Math.floor(Math.random() * mockEmails.length)];
 49→
 50→  const ga4Properties = [
 51→    'properties/345678901 - citedby.ai',
 52→    'properties/234567890 - mon-ecommerce.fr',
 53→    'properties/456789012 - app.saas-tool.com',
 54→  ];
 55→  const scSites = [
 56→    'https://citedby.ai',
 57→    'https://www.mon-ecommerce.fr',
 58→    'https://app.saas-tool.com',
 59→  ];
 60→
 61→  const property = isGA4
 62→    ? ga4Properties[Math.floor(Math.random() * ga4Properties.length)]
 63→    : scSites[Math.floor(Math.random() * scSites.length)];
 64→
 65→  const integration: Integration = {
 66→    id: randomId,
 67→    type,
 68→    name: isGA4 ? 'Google Analytics 4' : 'Google Search Console',
 69→    email,
 70→    property,
 71→    connectedAt: new Date().toISOString(),
 72→    status: 'connected',
 73→  };
 74→
 75→  const current = loadIntegrations().filter((i) => i.type !== type);
 76→  current.push(integration);
 77→  saveIntegrations(current);
 78→
 79→  return integration;
 80→}
